import React from 'react';
import clsx from 'clsx';
import { forwardHTMLRef } from '../../../util/forwardRef';
import { useCssScope } from '../../../config-provider/hooks';

const PickerHeader = forwardHTMLRef<unknown, 'div'>((props, ref) => {
  const { className, children, ...restProps } = props;
  const cssScope = useCssScope('picker');
  const prefixCls = cssScope();
  const headerPrefixCls = cssScope('-panel-header');
  return (
    <div ref={ref} {...restProps} className={clsx(headerPrefixCls, className)}>
      <div className={`${prefixCls}-panel-header-inner`}>{children}</div>
    </div>
  );
});

export default PickerHeader;
